// ─── SHOWROOM GALLERY (native horizontal scroll-snap — smooth on every device) ─
function Showroom() {
  const scrollerRef = useRef(null);
  const sectionRef = useRef(null);
  const inView = useInView(sectionRef, { once: true, margin: "-100px" });
  const [canLeft, setCanLeft] = useState(false);
  const [canRight, setCanRight] = useState(true);

  const pieces = [
    { img: IMG_THRONE, name: "Regal Throne Chair", note: "Hand-gilded frame" },
    { img: IMG_SMARTBED, name: "The Ultimate Smart Bed", note: "Built-in storage & speakers" },
    { img: IMG_DINING, name: "Heritage Dining Set", note: "Solid live-edge wood" },
    { img: IMG_TEALBED, name: "Teal Tufted Wing Bed", note: "Full button-tufting" },
    { img: IMG_WARDROBE, name: "Bespoke Wardrobe", note: "Made to your measurements" },
    { img: IMG_TVUNIT_MARBLE, name: "Marble-Panel TV Unit", note: "Ambient LED lighting" },
    { img: IMG_PINK_WARDROBE, name: "Kids' Pink Wardrobe", note: "With side shoe rack" },
  ];

  const checkScroll = () => {
    const el = scrollerRef.current;
    if (!el) return;
    setCanLeft(el.scrollLeft > 8);
    setCanRight(el.scrollLeft < el.scrollWidth - el.clientWidth - 8);
  };

  useEffect(() => { checkScroll(); }, []);

  const scrollByCard = (dir) => {
    const el = scrollerRef.current;
    if (!el) return;
    const card = el.querySelector("[data-card]");
    const amount = card ? card.offsetWidth + 32 : 400;
    el.scrollBy({ left: dir * amount, behavior: "smooth" });
  };

  return (
    <section id="showroom" ref={sectionRef} className="relative bg-[#1C1410] py-20 md:py-28 overflow-hidden">
      <div className="max-w-7xl mx-auto px-6 w-full mb-10 flex flex-col md:flex-row md:items-end md:justify-between gap-6">
        <motion.div variants={fadeUp()} initial="hidden" animate={inView ? "visible" : "hidden"}>
          <p className="text-[#B8743C] text-sm uppercase tracking-[0.3em] font-bold mb-3">Step Inside</p>
          <h2 className="font-serif text-4xl md:text-5xl font-bold text-[#F5EFE6]">The Virtual Showroom</h2>
          <p className="text-[#D9C9A8] mt-3 max-w-xl">Swipe or scroll through a curated selection of our most-loved pieces, exactly as they'd appear on our showroom floor.</p>
        </motion.div>

        {/* Desktop arrow controls */}
        <div className="hidden md:flex gap-3">
          <button onClick={() => scrollByCard(-1)} disabled={!canLeft}
            className={`w-11 h-11 rounded-full border flex items-center justify-center transition-colors ${canLeft ? "border-[#D9C9A8]/40 text-[#F5EFE6] hover:bg-[#F5EFE6] hover:text-[#1C1410]" : "border-[#D9C9A8]/10 text-[#D9C9A8]/20 cursor-not-allowed"}`}
          ><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7"/></svg></button>
          <button onClick={() => scrollByCard(1)} disabled={!canRight}
            className={`w-11 h-11 rounded-full border flex items-center justify-center transition-colors ${canRight ? "border-[#D9C9A8]/40 text-[#F5EFE6] hover:bg-[#F5EFE6] hover:text-[#1C1410]" : "border-[#D9C9A8]/10 text-[#D9C9A8]/20 cursor-not-allowed"}`}
          ><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7"/></svg></button>
        </div>
      </div>

      <div
        ref={scrollerRef}
        onScroll={checkScroll}
        className="flex gap-6 md:gap-8 px-6 overflow-x-auto pb-4 snap-x snap-mandatory scroll-smooth [-webkit-overflow-scrolling:touch] [scrollbar-width:none] [&::-webkit-scrollbar]:hidden"
      >
        {pieces.map((p, i) => (
          <motion.div key={p.name} data-card
            initial={{ opacity: 0, y: 24 }} animate={inView ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.6, delay: i * 0.08 }}
            className="relative shrink-0 w-[78vw] md:w-[34vw] lg:w-[30vw] h-[60vh] md:h-[55vh] max-h-[560px] rounded-3xl overflow-hidden shadow-2xl group snap-center"
          >
            <img src={p.img} alt={p.name} loading="lazy" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" />
            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/10 to-transparent" />
            <div className="absolute bottom-0 left-0 p-6">
              <span className="text-[#B8743C] text-xs font-bold uppercase tracking-widest">{String(i + 1).padStart(2, "0")}</span>
              <h3 className="font-serif text-2xl text-white font-bold mt-1">{p.name}</h3>
              <p className="text-white/60 text-sm mt-1">{p.note}</p>
            </div>
          </motion.div>
        ))}
        <div className="shrink-0 w-[78vw] md:w-[34vw] lg:w-[30vw] h-[60vh] md:h-[55vh] max-h-[560px] rounded-3xl border-2 border-dashed border-[#D9C9A8]/30 flex flex-col items-center justify-center text-center p-8 snap-center">
          <p className="text-[#D9C9A8] font-serif text-2xl mb-3">See the Full Collection</p>
          <a href="#products" className="text-[#B8743C] font-semibold border-b border-[#B8743C] pb-1">Browse All Pieces →</a>
        </div>
      </div>

      {/* Mobile swipe hint dots */}
      <div className="flex md:hidden justify-center gap-1.5 mt-5">
        {pieces.map((_, i) => <div key={i} className="w-1.5 h-1.5 rounded-full bg-[#D9C9A8]/30" />)}
      </div>

      {/* Inspect in 3D — real WebGL models */}
      <Inspect3DPanel />
    </section>
  );
}

function Inspect3DPanel() {
  const [active, setActive] = useState(0);
  const panelRef = useRef(null);
  const inView = useInView(panelRef, { once: true, margin: "-100px" });

  const models = [
    { url: MODEL_SHEEN_CHAIR, name: "Sheen Chair", note: "Real-time WebGL · drag to inspect" },
    { url: MODEL_DAMASK_CHAIR, name: "Damask Chair", note: "Real-time WebGL · drag to inspect" },
    { url: MODEL_LEATHER_SOFA, name: "Leather Sofa", note: "Real-time WebGL · drag to inspect" },
    { url: MODEL_BARN_LAMP, name: "Barn Lamp", note: "Real-time WebGL · drag to inspect" },
  ];

  return (
    <div ref={panelRef} className="max-w-7xl mx-auto px-6 mt-20 md:mt-28">
      <motion.div variants={fadeUp()} initial="hidden" animate={inView ? "visible" : "hidden"} className="flex flex-col md:flex-row md:items-end md:justify-between gap-4 mb-8">
        <div>
          <p className="text-[#B8743C] text-sm uppercase tracking-[0.3em] font-bold mb-3">True 3D</p>
          <h3 className="font-serif text-3xl md:text-4xl font-bold text-[#F5EFE6]">Inspect a Piece in 3D</h3>
          <p className="text-[#D9C9A8] mt-2 max-w-lg text-sm">A real, rotatable 3D model — not a photo. Drag to spin it around and see every angle, just like you would in our showroom.</p>
        </div>
        <div className="flex gap-2 flex-wrap">
          {models.map((m, i) => (
            <button key={m.name} onClick={() => setActive(i)}
              className={`px-4 py-2 rounded-full text-xs font-semibold border transition-colors ${active === i ? "bg-[#B8743C] text-[#1C1410] border-[#B8743C]" : "border-[#D9C9A8]/30 text-[#D9C9A8] hover:border-[#B8743C]"}`}
            >{m.name}</button>
          ))}
        </div>
      </motion.div>

      <motion.div variants={fadeUp(0.15)} initial="hidden" animate={inView ? "visible" : "hidden"}
        className="rounded-3xl overflow-hidden border border-[#D9C9A8]/15 bg-gradient-to-b from-[#241a14] to-[#1C1410]"
      >
        {/* Same persistent-viewer pattern as the hero: all 4 models preload once,
            switching tabs is a visibility toggle, not a reload. */}
        <ThreeDSlideshowViewer models={models} activeIndex={active} height="60vh" />
      </motion.div>
      <p className="text-center text-[#D9C9A8]/40 text-xs mt-3">{models[active].note}</p>
    </div>
  );
}

