// ─── PRODUCT CARD ─────────────────────────────────────────────────────────────
function ProductCard({ product, onQuickView }) {
  const { cart, addToCart, toggleWishlist, wishlist } = useContext(CartCtx);
  const wished = wishlist.includes(product.id);
  const inCart = cart.some((i) => i.id === product.id);

  return (
    <motion.div layout initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95 }}
      whileHover={{ y: -6 }} transition={{ type: "spring", stiffness: 300, damping: 22 }}
      className="group rounded-2xl overflow-hidden shadow-md hover:shadow-2xl transition-shadow duration-300 flex flex-col bg-white border border-[#D9C9A8]/40"
    >
      <div className="relative h-64 overflow-hidden cursor-pointer" onClick={() => onQuickView(product)}>
        <motion.img src={product.image} alt={product.name} loading="lazy" className="w-full h-full object-cover" whileHover={{ scale: 1.08 }} transition={{ duration: 0.5 }} />
        {product.badge && (
          <span className={`absolute top-3 left-3 text-[#F5EFE6] text-[10px] font-bold px-2.5 py-1 rounded-full ${product.badge === "SALE" ? "bg-[#B8743C]" : "bg-[#1C1410]"}`}>{product.badge}</span>
        )}
        <motion.div initial={{ opacity: 0 }} whileHover={{ opacity: 1 }} className="absolute inset-0 bg-black/20 flex items-center justify-center gap-3">
          <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.95 }}
            onClick={(e) => { e.stopPropagation(); addToCart(product); }}
            className={`w-11 h-11 rounded-full shadow-lg flex items-center justify-center transition-colors ${inCart ? "bg-[#1C1410] text-[#F5EFE6]" : "bg-white text-[#1C1410] hover:bg-[#B8743C] hover:text-white"}`}
          ><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"/></svg></motion.button>
          <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.95 }}
            onClick={(e) => { e.stopPropagation(); toggleWishlist(product.id); }}
            className={`w-11 h-11 rounded-full shadow-lg flex items-center justify-center transition-colors ${wished ? "bg-red-500 text-white" : "bg-white text-[#1C1410] hover:bg-red-500 hover:text-white"}`}
          ><svg className="w-4 h-4" fill={wished ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/></svg></motion.button>
          <motion.button whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.95 }}
            onClick={(e) => { e.stopPropagation(); onQuickView(product); }}
            className="w-11 h-11 bg-white text-[#1C1410] hover:bg-[#B8743C] hover:text-white rounded-full shadow-lg flex items-center justify-center transition-colors"
          ><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"/></svg></motion.button>
        </motion.div>
      </div>

      <div className="p-5 flex flex-col flex-1">
        <span className="text-[#B8743C] text-[10px] font-bold uppercase tracking-widest mb-1.5">{product.category}</span>
        <h3 className="font-serif font-bold text-base mb-2 cursor-pointer hover:text-[#B8743C] transition-colors text-[#1C1410]" onClick={() => onQuickView(product)}>{product.name}</h3>
        <div className="flex items-center gap-2 mb-4">
          <Stars count={product.rating} />
          <span className="text-xs text-gray-400">({product.reviews})</span>
        </div>
        <div className="mt-auto flex items-center justify-between gap-2">
          <div>
            <span className="text-lg font-bold text-[#1C1410]">{fmtNaira(product.price)}</span>
            {product.oldPrice && <span className="text-xs text-gray-400 line-through ml-1.5 block">{fmtNaira(product.oldPrice)}</span>}
          </div>
          <motion.button whileTap={{ scale: 0.95 }} onClick={() => addToCart(product)}
            className={`text-xs font-bold px-4 py-2 rounded-full transition-colors shrink-0 ${inCart ? "bg-[#1C1410] text-white" : "bg-[#1C1410]/10 text-[#1C1410] hover:bg-[#1C1410] hover:text-white"}`}
          >{inCart ? "In Cart" : "Add to Cart"}</motion.button>
        </div>
      </div>
    </motion.div>
  );
}

